71	const INSURANCE_VALUES: Record<string, number> = {
72	  sword: 1000,
73	  amulet: 600,
74	  staff: 800,
75	  potion: 400,
76	  rune: 250,
77	  moonstone: 250,
78	};
79	
80	const calculateInsuranceSum = (items: PolicyItem[]): number =>
81	  items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
82	
83	const calculatePayoutCap = (items: PolicyItem[]): number =>
84	  calculateInsuranceSum(items) * PAYOUT_CAP_MULTIPLIER;
85	
86	const COMPONENT_TYPES = ["rune", "moonstone"];
87	const BLOCK_SIZE = 3;
88	const BLOCK_PREMIUM = 60;
89	
90	const componentPremium = (type: string, count: number): number =>
91	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * basePremiumForType(type);
92	
93	const itemSurcharge = (item: PolicyItem): number => {
94	  const base = basePremiumForType(item.type);
95	  return (item.cursed ? base * CURSED_SURCHARGE_RATE : 0)
96	    + ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
97	};
98	
99	const countByType = (items: (PolicyItem | ComponentItem)[]): Record<string, number> =>
100	  items.reduce((counts: Record<string, number>, item) => {
101	    counts[item.type] = (counts[item.type] ?? 0) + 1;
102	    return counts;
103	  }, {});
104	
105	const isComponent = (item: PolicyItem | ComponentItem): boolean => COMPONENT_TYPES.includes(item.type);
106	
107	const calculateQuotePremium = (items: (PolicyItem | ComponentItem)[], customer: Customer, stepIndex: number): number => {
108	  const regularItems = items.filter((item): item is PolicyItem => !isComponent(item));
109	  const components = items.filter(isComponent);
110	
111	  const regularBasePremium = regularItems.reduce(
112	    (sum, item) => sum + basePremiumForType(item.type), 0);
113	  const componentBasePremium = Object.entries(countByType(components)).reduce(
114	    (sum, [type, count]) => sum + componentPremium(type, count), 0);
115	  const policyBasePremium = regularBasePremium + componentBasePremium;
116	
117	  const totalSurcharges = regularItems.reduce(
118	    (sum, item) => sum + itemSurcharge(item), 0);
119	
120	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
121	    ? policyBasePremium * LOYALTY_DISCOUNT_RATE
122	    : 0;
123	  const followUpDiscount = stepIndex > 0 ? policyBasePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
124	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
125	
126	  const premium = policyBasePremium + totalSurcharges - loyaltyDiscount
127	    + firstInsuranceSurcharge - followUpDiscount;
128	  return Math.ceil(premium + PROCESSING_FEE);
129	};
130	
131	const isHighEnchantment = (policyItem: PolicyItem): boolean =>
132	  (policyItem.enchantment ?? 0) >= CLAIM_ENCHANTMENT_THRESHOLD;
133	
134	const reimbursableAmount = (damage: Damage, policyItem: PolicyItem): number =>
135	  isHighEnchantment(policyItem)
136	    ? damage.amount * CLAIM_ENCHANTMENT_REIMBURSEMENT_RATE
137	    : damage.amount;
138	
139	const calculateClaimPayout = (damages: Damage[], policyItems: PolicyItem[], remainingCap: number): { payout: number; remainingCap: number } => {
140	  const uncappedPayout = damages.reduce((payout, damage) => {
141	    const policyItem = policyItems.find((item) => item.type === damage.type);
142	    if (!policyItem) return payout;
143	    return payout + Math.max(0, reimbursableAmount(damage, policyItem) - DEDUCTIBLE);
144	  }, 0);
145	  const payout = Math.floor(Math.min(uncappedPayout, remainingCap));
146	  return { payout, remainingCap: remainingCap - payout };
147	};
148	
149	export const processScenario = (scenario: Scenario): ScenarioResult => {
150	  let policyItems: PolicyItem[] = [];
151	  let remainingCap = 0;
152	  return {
153	    results: scenario.steps.map((step, index) => {
154	      if (step.op === "claim") {
155	        const result = calculateClaimPayout(step.damages, policyItems, remainingCap);
156	        remainingCap = result.remainingCap;
157	        return { payout: result.payout };
158	      }
159	      policyItems = step.items as PolicyItem[];
160	      remainingCap = calculatePayoutCap(policyItems);
161	      return { premium: calculateQuotePremium(step.items, scenario.customer, index) };
162	    }),
163	  };
164	};
